class Solution(object):
    def longestCommonPrefix(self, words):
        n = len(words)

        def lcp(a, b):
            l = 0
            while l < len(a) and l < len(b) and a[l] == b[l]:
                l += 1
            return l

        # Precompute adj[i] = lcp(words[i], words[i+1]) for i in 0..n-2
        adj = [lcp(words[i], words[i+1]) for i in range(n-1)]

        # prefix_max[i] = max(adj[0..i])
        prefix_max = [0] * (n - 1)
        if n > 1:
            prefix_max[0] = adj[0]
            for i in range(1, n-1):
                prefix_max[i] = max(prefix_max[i-1], adj[i])

        # suffix_max[i] = max(adj[i..n-2])
        suffix_max = [0] * (n - 1)
        if n > 1:
            suffix_max[n-2] = adj[n-2]
            for i in range(n-3, -1, -1):
                suffix_max[i] = max(suffix_max[i+1], adj[i])

        result = []
        for i in range(n):
            # Remove words[i]; adjacent pairs change: (i-1,i) and (i,i+1) are removed,
            # and new pair (i-1, i+1) is added.
            # Max over: all adj except those involving i, plus new pair if valid.
            parts = []
            # Max of adj[0..i-2]
            if i >= 2:
                parts.append(prefix_max[i-2])
            # Max of adj[i+1..n-2]
            if i <= n - 3:
                parts.append(suffix_max[i+1])
            # New adjacent pair (i-1, i+1)
            if i > 0 and i < n - 1:
                parts.append(lcp(words[i-1], words[i+1]))
            result.append(max(parts) if parts else 0)
        return result
